import{_ as t,o as n,c as o,a3 as r}from"./chunks/framework.CjquFG0V.js";const f=JSON.parse('{"title":"90A. Permanent Night Shift","description":"","frontmatter":{"title":"90A. Permanent Night Shift","eba":"Mental Health Services 2024-2028","topics":["hours","shift-work","staffing"]},"headers":[],"relativePath":"ebas/mental-health/rpn-pen-mho/hours-of-work/90A-permanent-night-shift.md","filePath":"ebas/mental-health/rpn-pen-mho/hours-of-work/90A-permanent-night-shift.md"}'),s={name:"ebas/mental-health/rpn-pen-mho/hours-of-work/90A-permanent-night-shift.md"};function i(a,e,h,p,l,m){return n(),o("div",null,[...e[0]||(e[0]=[r('<h1 id="_90a-permanent-night-shift" tabindex="-1">90A. Permanent Night Shift <a class="header-anchor" href="#_90a-permanent-night-shift" aria-label="Permalink to &quot;90A. Permanent Night Shift&quot;">​</a></h1><p>Note: This clause does not apply to casual Employees. It is the intent of this provision to maximise the use of permanent night shift employees. 90A.1. Permanent Night Shift Employment</p><p><strong>(a)</strong> In this clause, a permanent night shift employee means a full or part-time Employee who only works on night shift subject to the provisions of clause 90A.6.</p><p><strong>(b)</strong> Utilisation of permanent night shift employees will be the preferred approach to staffing at night wherever possible. 90A.2. Permanent Night Shift Employment – Employee Request</p><p><strong>(a)</strong> An Employee may make a written request to work permanent night shift and an Employer may only refuse on reasonable business grounds. Where an Employee makes a written request, the Employer will respond in writing within 21 days.</p><p><strong>(b)</strong> Where an Employer proposes to refuse the request on reasonable business grounds, the Employer will notify the Employee in writing of those reasonable business grounds and will offer to meet with the Employee to discuss the request before a decision is made.</p><p>90A.3. Permanent Night Shift Employment – Transitional</p><p><strong>(a)</strong> With respect to wards or units with a night shift, the Employer will advise Employees who, in the previous 12 months or prior to commencing any period of extended leave:</p><p><strong>(i)</strong> were working as permanent night shift employees as defined at clause</p><p><strong>90A.1</strong> that they will be appointed as permanent night shift employees before three months after the commencement of the Agreement, unless they indicate they do not wish to be so appointed.</p><p><strong>(ii)</strong> were working as permanent night shift employees as defined at clause</p><p><strong>90A.1</strong> as part of a temporary variation, flexible work arrangement or comparable situation (“the arrangement”) they will be appointed as permanent night shift for the duration of the arrangement in respect to that ward or unit.</p><p><strong>(iii)</strong> worked night shift other than as a permanent night shift employee (i.e. worked night shifts and other shifts) to express an interest in continuing to work night shifts, and the amount of night shift they wish to continue working.</p><p><strong>(b)</strong> Employees at (iii) above will, where practicable, be offered night shifts in accordance with their expressed amount of desired night shift, in respect to that ward or unit.</p><p><strong>(c)</strong> Following the process described at subclause 90A.3(a), the Employer will seek expressions of interest from Employees with respect to the remaining night shifts necessary to meet the night shift staffing requirements for that ward or unit before 4 months after the commencement of the Agreement.</p><p><strong>(d)</strong> In responding to expressions of interest, subject to any skill mix or ANUM requirements, full or part time staff for whom the ward is their Base Ward/Unit will be preferred in determining permanent night shift status.</p><p><strong>(e)</strong> The Employer will provide progress reports to the WIC of progress in implementing this clause. 90A.4. Post transition - Permanent Night Shift Employment Vacancy Where a vacancy (whether permanent or temporary) on night shift occurs after the period referred to in 90A.3(a)(i), the Employer will seek to fill it with a permanent night shift employee.</p><p>90A.5. Provision of education to permanent night shift employees</p><p><strong>(a)</strong> Wherever practicable, permanent night shift employees will be offered education during their night shift.</p><p><strong>(b)</strong> Where this is not practicable and it is necessary to roster the Employee to shifts other than night shift for the purpose of providing education, this will occur without loss of income to the Employee.</p><p><strong>(c)</strong> Nothing in this clause is intended to alter an Employer&#39;s rights regarding undertaking performance management in accordance with <a href="/eba/ebas/mental-health/common-terms/consultation-disputes/24-managing-conduct-and-performance.html">clause 24</a> to support Employees. Performance management has the same meaning as set out at subclauses 24.6(b) and (c) of this Agreement. 90A.6. Other provisions</p><p><strong>(a)</strong> Unless 90A.6(b) applies, where an Employer seeks to end an Employee’s status as a permanent night shift employee, the provisions of 18 (Consultation) shall apply and a notice period of not less than 8 weeks will be provided.</p><p><strong>(b)</strong> Where an additional employee/s seeks to become a permanent night shift employee/s, the Employer will review the allocation to permanent nights in accordance with the process contained at 19 (Consultation about Changes to Rosters or Hours of Work) and any amended arrangement will apply from the release of the next roster.</p><p><strong>(c)</strong> An Employee who is a permanent night shift worker must have a minimum 47 hours break before working other shifts unless requested by the Employer to return earlier. 90A.7. Review The Employers will work with the Unions to evaluate the changes above to ensure there are no unintended consequences, with reports being provided to the WIC.</p>',24)])])}const c=t(s,[["render",i]]);export{f as __pageData,c as default};
